@stereotype(CIMStereotype.GridAPPSD)
@stereotype(CIMStereotype.enumeration)
@stereotype(CIMStereotype.Attribute)
class ConnectivityAreaKind(Enum):
    '''
    '''

    distributionArea = 'distributionArea'
    '''
    A topologically continuous grouping of distribution feeders, typically
    divided by normal-open switches. The DistributionArea provides the
    highest-level description of the equipment controlled by the Distribution
    System Operator (DSO)
    '''
    
    feederArea = 'feederArea'
    '''
    The FeederArea contains all medium voltage equipment not contained
    in a SwitchArea or Substation / Bay. It also includes all Sectionalisers,
    Reclosers, and all other poletop and pad-mounted switchgear that form
    the boundary of a SwitchArea. It also includes all equipment between
    the feeder head terminal and the first switching device if the substation
    breaker is not included in Feeder EquipmentContainer
    '''
    
    microgrid = 'microgrid'
    '''
    Containment of distribution equipment that 1) has clearly-defined electrical
    boundaries formed by one or more point of common coupling Switch objects
    and 2) that acts as a single controllable entity which can be operated
    in grid-connected or islanded mode. This covers both utility-owned
    distribution microgrids and customer-owned facility microgrids as defined
    in IEV 617-04-22.
    '''
    
    secondaryArea = 'secondaryArea'
    '''
    Containment of low-voltage distribution Equipment and customer-owned
    Equipment with clearly defined electrical boundaries formed by the
    low-side terminal(s) of one or more PowerTransformer objects.
    '''
    
    switchArea = 'switchArea'
    '''
    Containment of medium-voltage distribution Equipment with clearly defined
    electrical boundaries formed by one or more Switch objects. The SwitchArea
    contains all conductors, fuses, poletop equipment, and vault equipment.
    It also contains all secondary service transformers not contained in
    a SecondarySubstation.
    '''
    
    transmissionArea = 'transmissionArea'
    '''
    The connectivity-based grouping of equipment forming a transmission
    system operator's area of responsibility
    '''
    
    @property
    def __namespace__(self):
        return 'http://gridappsd.org/CIM/extension#'
    @property
    def __package__(self):
        return 'TopologyEXT'
    @property
    def __minOccurs__(self):
        return '0'
    @property
    def __maxOccurs__(self):
        return 'unbounded'
    
